SELECT 
FROM dormitory
WHERE deleted_at IS NULL

    AND dormitory_id = #{dormitoryId}


    AND name ILIKE CONCAT('%', #{name}, '%')


    AND gender_type = #{genderType}


    AND region = #{region}


    AND address ILIKE CONCAT('%', #{address}, '%')

ORDER BY dormitory_id
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM dormitory
WHERE deleted_at IS NULL

    AND dormitory_id = #{dormitoryId}


    AND name ILIKE CONCAT('%', #{name}, '%')


    AND gender_type = #{genderType}


    AND region = #{region}


    AND address ILIKE CONCAT('%', #{address}, '%')

SELECT 
FROM dormitory
WHERE deleted_at IS NULL

    AND region IN

        #{region}



    AND dormitory_id = #{dormitoryId}


    AND gender_type = #{genderType}

ORDER BY name
